import{c as e,Q as r,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse(`{"title":"Karpathy's CLAUDE.md - 4 Principles for Better LLM Coding","description":"","frontmatter":{"url":"https://lucaberton.com/blog/karpathy-claude-md-llm-coding-principles-2026/","title":"Karpathy's CLAUDE.md - 4 Principles for Better LLM Coding","author":"Luca Berton","date":2026,"status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/06-lucaberton-four-rules-fix-llm.md","filePath":"research/ai-articles/06-lucaberton-four-rules-fix-llm.md","lastUpdated":1779894392000}`),l={name:"research/ai-articles/06-lucaberton-four-rules-fix-llm.md"};function i(n,t,s,p,c,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="karpathy-s-claude-md-4-principles-for-better-llm-coding" tabindex="-1">Karpathy&#39;s CLAUDE.md: 4 Principles for Better LLM Coding <a class="header-anchor" href="#karpathy-s-claude-md-4-principles-for-better-llm-coding" aria-label="Permalink to &quot;Karpathy&#39;s CLAUDE.md: 4 Principles for Better LLM Coding&quot;">​</a></h1><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本文系統地介紹了 Andrej Karpathy 識別的四項可預測的 LLM 編碼失敗模式，以及通過編寫 <code>CLAUDE.md</code> 檔案中的行為約束如何有效解決這些問題。該文章強調了從命令式指示向聲明式目標轉變的重要性。</p><p><strong>四項失敗模式與對應解決方案</strong></p><p><strong>1. 無聲假設 (Silent Assumptions)</strong></p><p>問題：LLM 在模糊的需求面前做出假設並盲目執行，而不尋求澄清。</p><p>解決方案「編碼前思考（Think Before Coding）」：要求模型在實施前明確陳述其理解的假設，並呈現可選的解釋。這防止了構建錯誤解決方案所浪費的時間和努力。</p><p><strong>2. 過度複雜化 (Overcomplexity)</strong></p><p>問題：LLM 傾向於添加不必要的功能、創建過度靈活的設計、以及構建不會被重複使用的抽象層。</p><p>解決方案「簡潔優先（Simplicity First）」：編碼約束規定「最小化代碼解決問題」。不添加投機性功能，不為未來可能需要而預先鋪設支持。這直接對應於資深工程師的最佳實踐：「做最簡單的能工作的事情」。</p><p><strong>3. 範圍蔓延 (Scope Creep)</strong></p><p>問題：修改現有代碼時，LLM 會改進不相關的函式或重新格式化超出任務範圍的代碼。</p><p>解決方案「精準修改（Surgical Changes）」：約束要求只觸及必要部分，保留既有的代碼風格，避免在相鄰函式上進行改進。每一行改動都應能直接追溯至用戶請求。</p><p><strong>4. 模糊執行 (Vague Execution)</strong></p><p>問題：任務定義不清晰，AI 代理無法判斷何時完成，導致過度或不足執行。</p><p>解決方案「目標驅動執行（Goal-Driven Execution）」：將模糊的命令轉化為具體的、可驗證的成功標準。而不是「修復這個 bug」，改為「寫一個複現該 bug 的測試，然後讓測試通過」。這種方法使模型能獨立地反覆迭代直至達成明確的目標。</p><p><strong>為什麼有效</strong></p><p>該方法之所以有效，在於：</p><ol><li><strong>零依賴</strong>：無需新工具或額外配置，Claude Code 原生支持項目級的指令檔案</li><li><strong>通用適用</strong>：這些原則適用於所有 AI 編碼工具，並與資深工程師的實踐對齊</li><li><strong>強制執行</strong>：作為項目配置檔案，這些原則在每個會話自動加載和執行</li></ol><p><strong>廣泛影響</strong></p><p>Karpathy 指出的原則不僅限於代碼生成。相同的思維框架也適用於：</p><ul><li>內容創作（新聞、文章生成）</li><li>圖像生成（設計規範、視覺指南）</li><li>影片製作（腳本、編輯指令）</li></ul><p>所有這些領域中，AI 工具都可能用不驗證的假設填充模糊的請求。</p><h2 id="關鍵引述" tabindex="-1">關鍵引述 <a class="header-anchor" href="#關鍵引述" aria-label="Permalink to &quot;關鍵引述&quot;">​</a></h2><blockquote><p>&quot;The models make wrong assumptions on your behalf and just run along with them without checking.&quot; — Andrej Karpathy（AI 編碼的根本問題）</p></blockquote><blockquote><p>&quot;They really like to overcomplicate code and APIs, bloat abstractions...&quot; — Andrej Karpathy（過度工程的典型表現）</p></blockquote><blockquote><p>&quot;State assumptions explicitly and seek clarification before implementation rather than silently proceeding with interpretations&quot; — Think Before Coding 的核心實踐</p></blockquote><h2 id="實踐價值" tabindex="-1">實踐價值 <a class="header-anchor" href="#實踐價值" aria-label="Permalink to &quot;實踐價值&quot;">​</a></h2><ul><li><strong>立即可用</strong>：複製 CLAUDE.md 到項目根目錄</li><li><strong>持續有效</strong>：在每個 Claude Code 會話自動加載</li><li><strong>可定制</strong>：根據項目需求調整原則</li><li><strong>無破壞</strong>：與現有工作流完全相容</li></ul>',29)])])}const g=e(l,[["render",i]]);export{h as __pageData,g as default};
